<template>
  <AppLayout>
    <main class="practice" v-loading="loading">
      <template v-if="!assessment">
        <header class="hero">
          <div><p class="eyebrow">CODE PRACTICE</p><h1>代码实训</h1><p>从已完成的章节开始练习，编程语言会根据课程内容自动匹配。</p></div>
        </header>

        <section v-if="catalog.chapters?.length" class="launchpad">
          <div class="section-head"><span>01</span><div><h2>选择练习内容</h2><p>这里只展示已经通过章节测验的内容</p></div></div>
          <div class="chapter-options">
            <button v-for="chapter in catalog.chapters" :key="chapter.chapter_doc_id" :class="{selected:form.chapter_doc_id===chapter.chapter_doc_id}" @click="selectChapter(chapter)">
              <span class="course-code">{{ shortCourse(chapter.course_title) }}</span><div><strong>{{ chapter.title }}</strong><small>{{ chapter.course_title }} · 已完成</small></div><i>{{ form.chapter_doc_id===chapter.chapter_doc_id?'✓':'→' }}</i>
            </button>
          </div>

          <div v-if="selectedChapter" class="configuration">
            <section class="config-card language-config"><div class="section-head compact"><span>02</span><div><h2>编程语言</h2><p>{{ selectedChapter.policy==='fixed'?'已根据课程自动匹配':'通用算法可自主选择' }}</p></div></div>
              <div v-if="selectedChapter.policy==='fixed'" class="locked-language"><b>{{ languageLabel(form.language) }}</b><div><strong>{{ selectedChapter.course_title }} 使用 {{ languageLabel(form.language) }}</strong><small>语言由课程内容决定，无法切换</small></div><span>已锁定</span></div>
              <div v-else class="language-options"><button v-for="language in selectedChapter.allowed_languages" :key="language" :disabled="!catalog.runtimes?.[language]" :class="{selected:form.language===language}" @click="form.language=language">{{ languageLabel(language) }}</button></div>
            </section>

            <section class="config-card"><div class="section-head compact"><span>03</span><div><h2>提交模式</h2><p>选择你更熟悉的作答方式</p></div></div>
              <div class="mode-options"><button :class="{selected:form.mode==='acm'}" @click="form.mode='acm'"><strong>完整代码</strong><small>自行处理输入与输出</small></button><button :class="{selected:form.mode==='leetcode'}" @click="form.mode='leetcode'"><strong>核心代码</strong><small>只补全函数并返回结果</small></button></div>
            </section>
          </div>
          <div class="launch-action"><p v-if="selectedChapter">将使用 <strong>{{ languageLabel(form.language) }}</strong> 生成一道 {{ form.mode==='acm'?'完整代码':'核心代码' }}练习</p><el-button type="primary" size="large" :disabled="!selectedChapter||!catalog.runtimes?.[form.language]" :loading="creating" @click="create(false)">生成实训题 <span>→</span></el-button></div>
        </section>
        <el-empty v-else-if="!loading" description="先完成至少一个章节测验，再来开始代码实训" />
      </template>

      <template v-else>
        <header class="studio-bar"><div><button class="back" @click="assessment=null">← 返回选择</button><span>{{ selectedChapter?.course_title || '课程实训' }}</span><b>/</b><strong>{{ task.title }}</strong></div><div class="studio-tags"><span>{{ languageLabel(assessment.blueprint?.language) }}</span><span>{{ assessment.blueprint?.mode==='acm'?'完整代码':'核心代码' }}</span></div></header>
        <section class="studio">
          <aside class="brief"><p class="eyebrow">MISSION</p><h1>{{ task.title }}</h1><p class="description">{{ task.description }}</p><div class="brief-block"><h3>任务要求</h3><p>{{ task.prompt }}</p></div><div v-if="assessment.blueprint?.mode==='leetcode'" class="return-tip"><strong>只返回结果</strong><p>不要读取标准输入，也不要打印输出；评测器会调用你的函数。</p></div><div class="brief-block"><h3>约束</h3><p>{{ task.constraints }}</p></div><div class="sample"><span>示例</span><pre v-if="sample">输入  {{ sample.input }}输出  {{ sample.expected }}</pre></div></aside>
          <section class="workbench"><div class="editor-toolbar"><div><i></i><strong>main.{{ fileExtension }}</strong><span>{{ languageLabel(assessment.blueprint?.language) }}</span></div><button @click="resetCode">恢复初始代码</button></div><textarea v-model="code" spellcheck="false"/><div class="submit-bar"><span>代码将在隔离环境中编译并运行</span><el-button type="primary" size="large" :loading="submitting" @click="submit">运行并提交</el-button></div>
            <article v-if="result" :class="['result-panel',result.passed?'passed':'failed']"><header><div><span>{{ result.passed?'✓':'!' }}</span><div><strong>{{ verdictTitle(result.verdict) }}</strong><small>{{ result.feedback }}</small></div></div><b>{{ result.score }}<small>分</small></b></header><div v-if="result.cases?.length" class="case-grid"><div v-for="item in result.cases" :key="item.index" :class="{passed:item.passed}"><span>测试 {{ item.index }}</span><strong>{{ item.passed?'通过':item.exit_code?'运行错误':'答案错误' }}</strong><small v-if="!item.passed&&!item.exit_code">期望 {{ item.expected }} · 实际 {{ item.actual || '无输出' }}</small><small v-else-if="item.passed">输出 {{ item.actual }}</small></div></div><details v-if="result.trace?.length"><summary>查看完整评测过程</summary><ol><li v-for="(item,index) in result.trace" :key="index"><strong>{{ item.stage }}</strong><span>{{ item.detail }}</span></li></ol></details></article>
          </section>
        </section>
      </template>

      <el-dialog v-model="generating" width="min(92vw,520px)" :close-on-click-modal="false" :show-close="false"><GenerationSteps :active-step="activeStep" :done="generationDone" /></el-dialog>
      <el-dialog v-model="evaluating" width="min(92vw,560px)" :close-on-click-modal="false" :close-on-press-escape="false" :show-close="false"><div class="evaluation"><p class="eyebrow">CODE EVALUATION</p><h2>代码评测 Agent 正在执行</h2><p>正在隔离环境中运行你的原始代码，不会修改源码。</p><ol><li v-for="(item,index) in evaluationEvents" :key="`${item.stage}-${index}`" :class="item.status"><span>{{ item.status==='passed'?'✓':item.status==='failed'?'!':'…' }}</span><div><strong>{{ item.stage }}</strong><small>{{ item.detail }}</small></div></li></ol><div v-if="!evaluationEvents.length" class="waiting">正在建立隔离运行环境…</div></div></el-dialog>
    </main>
  </AppLayout>
</template>

<script setup>
import { computed, onMounted, ref } from 'vue'
import { useRoute } from 'vue-router'
import { ElMessage } from 'element-plus'
import AppLayout from '../components/AppLayout.vue'
import GenerationSteps from '../components/GenerationSteps.vue'
import { apiGet, apiPost, streamCodeEvaluation } from '../utils/api'

const route=useRoute()
const loading=ref(false),creating=ref(false),submitting=ref(false),catalog=ref({chapters:[],runtimes:{}}),assessment=ref(null),code=ref(''),result=ref(null),generating=ref(false),activeStep=ref(0),generationDone=ref(false),evaluating=ref(false),evaluationEvents=ref([])
const form=ref({chapter_doc_id:route.query.chapter||'',language:null,mode:'acm'})
const selectedChapter=computed(()=>catalog.value.chapters?.find(item=>item.chapter_doc_id===form.value.chapter_doc_id)||null)
const task=computed(()=>assessment.value?.blueprint?.task||{}),sample=computed(()=>task.value.test_cases?.[0])
const fileExtension=computed(()=>({python:'py',c:'c',cpp:'cpp',java:'java'})[assessment.value?.blueprint?.language]||'txt')
const labels={python:'Python',c:'C',cpp:'C++',java:'Java'}
function languageLabel(language){return labels[language]||language||'自动匹配'}
function shortCourse(title){return ({Python:'PY','C 语言':'C','C++':'C++',Java:'JV','PyTorch':'PT','机器学习':'ML'})[title]||title.slice(0,2).toUpperCase()}
function selectChapter(chapter){form.value.chapter_doc_id=chapter.chapter_doc_id;form.value.language=chapter.recommended_language}
function verdictTitle(verdict){return {accepted:'评测通过',wrong_answer:'答案错误',compile_error:'编译错误',runtime_error:'运行错误',time_limit:'运行超时',rejected:'提交被拒绝',invalid_submission:'代码格式错误',runtime_unavailable:'运行环境不可用',runner_error:'评测服务异常'}[verdict]||'评测未通过'}
async function load(){loading.value=true;try{catalog.value=await apiGet('/learning/code-practice/catalog');const initial=selectedChapter.value||catalog.value.chapters?.[0];if(initial)selectChapter(initial)}catch(error){ElMessage.error(error.message||'实训目录加载失败')}finally{loading.value=false}}
async function create(replace=false){creating.value=true;generating.value=true;generationDone.value=false;activeStep.value=0;const timer=setInterval(()=>{if(activeStep.value<3)activeStep.value++},700);try{const data=await apiPost('/learning/code-practice',{chapter_doc_id:form.value.chapter_doc_id,language:form.value.language,mode:form.value.mode,replace_previous:replace});assessment.value=data.assessment;code.value=task.value.starter_code||'';result.value=null;generationDone.value=true;activeStep.value=3;setTimeout(()=>{generating.value=false},350)}catch(error){ElMessage.error(error.message||'实训题生成失败');generating.value=false}finally{clearInterval(timer);creating.value=false}}
function resetCode(){code.value=task.value.starter_code||''}
async function submit(){submitting.value=true;evaluating.value=true;evaluationEvents.value=[];try{result.value=await streamCodeEvaluation(assessment.value.id,code.value,event=>{if(event.type==='progress')evaluationEvents.value.push(event)});assessment.value.status=result.value.passed?'passed':'failed';setTimeout(()=>{evaluating.value=false},450)}catch(error){evaluating.value=false;ElMessage.error(error.message||'评测失败')}finally{submitting.value=false}}
onMounted(load)
</script>

